   354→                        globalShortcutManager.setRecordingMode('toggle');
   355→                        rebuildTrayMenu();
   356→                    },
   357→                },
   358→            ],
   359→        },
   360→        {
   361→            label: 'Transcription Mode',
   362→            submenu: [
   363→                {
   364→                    label: '📝 Raw — Brut',
   365→                    type: 'radio',
   366→                    checked: currentMode === 'raw',
   367→                    click: () => {
   368→                        settingsManager.setSetting('transcriptionMode', 'raw');
   369→                        rebuildTrayMenu();
   370→                    },
   371→                },
   372→                {
   373→                    label: '✨ Clean — Propre',
   374→                    type: 'radio',
   375→                    checked: currentMode === 'clean',
   376→                    click: () => {
   377→                        settingsManager.setSetting('transcriptionMode', 'clean');
   378→                        rebuildTrayMenu();
   379→                    },
   380→                },
   381→                {
   382→                    label: '💼 Rewrite — Pro',
   383→                    type: 'radio',
   384→                    checked: currentMode === 'rewrite',
   385→                    click: () => {
   386→                        settingsManager.setSetting('transcriptionMode', 'rewrite');
   387→                        rebuildTrayMenu();
   388→                    },
   389→                },
   390→            ],
   391→        },
   392→        { type: 'separator' },
   393→        {
   394→            label: stealth ? '👻 Stealth Mode ✓' : '🎯 Overlay Mode',
   395→            click: () => {
   396→                settingsManager.setSetting('stealthMode', !stealth);
   397→                rebuildTrayMenu();
   398→            },
   399→        },
   400→        { type: 'separator' },
   401→        {
   402→            label: 'Settings',
   403→            click: () => createSettingsWindow(),
   404→        },
   405→        {
   406→            label: 'Quit',
   407→            click: () => app.quit(),
   408→        },
   409→    ]);
   410→
   411→    tray.setContextMenu(contextMenu);
   412→}
