     1→import { uIOhook, UiohookKey } from 'uiohook-napi';
     2→import { settingsManager, ShortcutKeys, RecordingMode } from '../config/settings';
     3→import { windowManager } from './windowManager';
     4→
     5→type RecordingCallback = () => void;
     6→
     7→/**
     8→ * Global keyboard shortcut manager with configurable shortcuts and modes.
     9→ */
    10→class GlobalShortcutManager {
    11→    private isRecording = false;
    12→    private recordingMode: RecordingMode = 'push-to-talk';
    13→    private shortcutKeys: ShortcutKeys = {
    14→        modifiers: ['command', 'shift'],
    15→        key: 'Space',
    16→    };
    17→
    18→    private onStartCallback: RecordingCallback | null = null;
    19→    private onStopCallback: RecordingCallback | null = null;
    20→
    21→    /**
    22→     * Set callbacks for recording start/stop
    23→     */
    24→    setCallbacks(onStart: RecordingCallback, onStop: RecordingCallback): void {
    25→        this.onStartCallback = onStart;
    26→        this.onStopCallback = onStop;
    27→    }
    28→
    29→    /**
    30→     * Register global keyboard hooks with current settings
    31→     */
    32→    register(): void {
    33→        try {
    34→            // Load settings
    35→            const settings = settingsManager.getSettings();
    36→            this.recordingMode = settings.recordingMode;
    37→            this.shortcutKeys = settings.shortcutKeys;
    38→
    39→            uIOhook.on('keydown', (event) => this.handleKeyDown(event));
    40→            uIOhook.on('keyup', (event) => this.handleKeyUp(event));
    41→            uIOhook.start();
    42→            console.log(`Global shortcuts registered: ${this.getShortcutString()}, mode: ${this.recordingMode}`);
    43→        } catch (error) {
    44→            console.error('Failed to register global shortcuts:', error);
    45→        }
    46→    }
    47→
    48→    /**
    49→     * Unregister global hooks
    50→     */
    51→    unregister(): void {
    52→        try {
    53→            uIOhook.stop();
    54→            console.log('Global shortcuts unregistered');
    55→        } catch (error) {
    56→            console.error('Failed to unregister shortcuts:', error);
    57→        }
    58→    }
    59→
    60→    /**
    61→     * Update shortcut keys dynamically
    62→     */
    63→    updateShortcut(keys: ShortcutKeys): void {
    64→        this.unregister();
    65→        this.shortcutKeys = keys;
    66→        this.register();
    67→        console.log(`Shortcut updated to: ${this.getShortcutString()}`);
    68→    }
    69→
    70→    /**
    71→     * Update recording mode dynamically
    72→     */
    73→    setRecordingMode(mode: RecordingMode): void {
    74→        this.recordingMode = mode;
    75→        console.log(`Recording mode set to: ${mode}`);
    76→
    77→        // Notify renderer
    78→        windowManager.sendToRenderer('recording-mode-changed', {
    79→            mode: mode,
    80→        });
    81→    }
    82→
    83→    /**
    84→     * Get current shortcut as human-readable string
    85→     */
    86→    getShortcutString(): string {
    87→        const modStr = this.shortcutKeys.modifiers
    88→            .map(m => m.charAt(0).toUpperCase() + m.slice(1))
    89→            .join('+');
    90→        return `${modStr}+${this.shortcutKeys.key}`;
    91→    }
    92→
    93→    /**
    94→     * Check if the current key event matches the configured shortcut
    95→     */
    96→    private isShortcutPressed(event: any): boolean {
    97→        // Check that all configured modifiers are pressed
    98→        const hasCommand = this.shortcutKeys.modifiers.includes('command') ? event.metaKey : !event.metaKey;
    99→        const hasControl = this.shortcutKeys.modifiers.includes('control') ? event.ctrlKey : !event.ctrlKey;
   100→        const hasShift = this.shortcutKeys.modifiers.includes('shift') ? event.shiftKey : !event.shiftKey;
   101→        const hasAlt = this.shortcutKeys.modifiers.includes('alt') ? event.altKey : !event.altKey;
   102→
   103→        // Map key name to keycode (simplified mapping)
   104→        const keyMatch = this.matchesKey(event.keycode, this.shortcutKeys.key);
   105→
   106→        return hasCommand && hasControl && hasShift && hasAlt && keyMatch;
   107→    }
   108→
   109→    /**
   110→     * Match keycode to key name
   111→     */
   112→    private matchesKey(keycode: number, keyName: string): boolean {
   113→        const keyMap: Record<string, number> = {
   114→            'Space': 57,
   115→            'R': 19,
   116→            'T': 20,
   117→            'S': 31,
   118→            'A': 30,
   119→            'D': 32,
   120→            'F': 33,
   121→            'G': 34,
   122→            // Add more as needed
   123→        };
   124→        return keyMap[keyName] === keycode;
   125→    }
   126→
   127→    private handleKeyDown(event: any): void {
   128→        if (!this.isShortcutPressed(event)) return;
   129→
   130→        if (this.recordingMode === 'push-to-talk') {
   131→            // Push-to-talk: start on keydown
   132→            if (!this.isRecording) {
   133→                this.startRecording();
   134→            }
   135→        } else {
   136→            // Toggle mode: toggle on keydown
   137→            if (this.isRecording) {
   138→                this.stopRecording();
   139→            } else {
   140→                this.startRecording();
   141→            }
   142→        }
   143→    }
   144→
   145→    private handleKeyUp(event: any): void {
   146→        if (!this.isShortcutPressed(event)) return;
   147→
   148→        // Only stop on keyup in push-to-talk mode
   149→        if (this.recordingMode === 'push-to-talk' && this.isRecording) {
   150→            this.stopRecording();
   151→        }
   152→    }
   153→
   154→    private startRecording(): void {
   155→        this.isRecording = true;
   156→        windowManager.sendToRenderer('shortcut-pressed', {});
   157→
   158→        if (this.onStartCallback) {
   159→            this.onStartCallback();
   160→        }
   161→    }
   162→
   163→    private stopRecording(): void {
   164→        this.isRecording = false;
   165→        windowManager.sendToRenderer('shortcut-released', {});
   166→
   167→        if (this.onStopCallback) {
   168→            this.onStopCallback();
   169→        }
   170→    }
   171→}
   172→
   173→export const globalShortcutManager = new GlobalShortcutManager();
