     1→import WebSocket from 'ws';
     2→import { EventEmitter } from 'events';
     3→import {
     4→    REALTIME_API_URL,
     5→    REALTIME_TRANSCRIPTION_MODEL,
     6→    AUDIO_SAMPLE_RATE,
     7→} from '../config/constants';
     8→
     9→/**
    10→ * Events emitted by StreamingTranscription:
    11→ *   'delta'     → { text: string, itemId: string } — incremental transcript
    12→ *   'completed' → { text: string, itemId: string } — final transcript for a turn
    13→ *   'error'     → { message: string }
    14→ *   'connected' → {}
    15→ *   'closed'    → {}
    16→ */
    17→class StreamingTranscription extends EventEmitter {
    18→    private ws: WebSocket | null = null;
    19→    private isConnected = false;
    20→    private reconnectTimeout: NodeJS.Timeout | null = null;
    21→
    22→    /**
    23→     * Open a WebSocket to the OpenAI Realtime transcription endpoint
    24→     */
    25→    connect(apiKey: string, language: string = 'auto'): void {
    26→        if (this.ws) {
    27→            this.disconnect();
    28→        }
    29→
    30→        console.log('[StreamingTranscription] Connecting to Realtime API...');
    31→
    32→        this.ws = new WebSocket(REALTIME_API_URL, {
    33→            headers: {
    34→                Authorization: `Bearer ${apiKey}`,
    35→                'OpenAI-Beta': 'realtime=v1',
    36→            },
    37→        });
    38→
    39→        this.ws.on('open', () => {
    40→            this.isConnected = true;
    41→            console.log('[StreamingTranscription] WebSocket connected');
    42→
    43→            // Configure session for transcription-only mode
    44→            const sessionConfig: any = {
    45→                type: 'session.update',
    46→                session: {
    47→                    type: 'transcription',
    48→                    audio: {
    49→                        input: {
    50→                            format: {
    51→                                type: 'audio/pcm',
    52→                                rate: AUDIO_SAMPLE_RATE, // 24000
    53→                            },
    54→                            noise_reduction: {
    55→                                type: 'near_field',
    56→                            },
    57→                            transcription: {
    58→                                model: REALTIME_TRANSCRIPTION_MODEL,
    59→                            },
    60→                            turn_detection: {
    61→                                type: 'server_vad',
    62→                                threshold: 0.5,
    63→                                prefix_padding_ms: 300,
    64→                                silence_duration_ms: 500,
    65→                            },
    66→                        },
    67→                    },
    68→                },
    69→            };
    70→
    71→            // Add language if not auto-detect
    72→            if (language !== 'auto') {
    73→                sessionConfig.session.audio.input.transcription.language = language;
    74→            }
    75→
    76→            this.ws!.send(JSON.stringify(sessionConfig));
    77→            this.emit('connected');
    78→        });
    79→
    80→        this.ws.on('message', (data: WebSocket.Data) => {
    81→            try {
    82→                const event = JSON.parse(data.toString());
    83→                this.handleServerEvent(event);
    84→            } catch (err) {
    85→                console.error('[StreamingTranscription] Failed to parse event:', err);
    86→            }
    87→        });
    88→
    89→        this.ws.on('error', (error: Error) => {
    90→            console.error('[StreamingTranscription] WebSocket error:', error.message);
    91→            this.emit('error', { message: error.message });
    92→        });
    93→
    94→        this.ws.on('close', (code: number, reason: Buffer) => {
    95→            console.log(`[StreamingTranscription] WebSocket closed: ${code} ${reason.toString()}`);
    96→            this.isConnected = false;
    97→            this.ws = null;
    98→            this.emit('closed');
    99→        });
   100→    }
   101→
   102→    /**
   103→     * Send a chunk of PCM16 audio (raw Int16 samples) as base64
   104→     */
   105→    sendAudioChunk(pcmBuffer: Buffer): void {
   106→        if (!this.ws || !this.isConnected) return;
   107→
   108→        const base64Audio = pcmBuffer.toString('base64');
   109→
   110→        this.ws.send(JSON.stringify({
   111→            type: 'input_audio_buffer.append',
   112→            audio: base64Audio,
   113→        }));
   114→    }
   115→
   116→    /**
   117→     * Manually commit the audio buffer (used when VAD is disabled)
   118→     */
   119→    commitAudioBuffer(): void {
   120→        if (!this.ws || !this.isConnected) return;
   121→
   122→        this.ws.send(JSON.stringify({
   123→            type: 'input_audio_buffer.commit',
   124→        }));
   125→    }
   126→
   127→    /**
   128→     * Disconnect from the Realtime API
   129→     */
   130→    disconnect(): void {
   131→        if (this.reconnectTimeout) {
   132→            clearTimeout(this.reconnectTimeout);
   133→            this.reconnectTimeout = null;
   134→        }
   135→
   136→        if (this.ws) {
   137→            this.isConnected = false;
   138→            this.ws.close();
   139→            this.ws = null;
   140→        }
   141→    }
   142→
   143→    /**
   144→     * Whether the WebSocket is currently connected
   145→     */
   146→    get connected(): boolean {
   147→        return this.isConnected;
   148→    }
   149→
   150→    /**
   151→     * Handle incoming server events
   152→     */
   153→    private handleServerEvent(event: any): void {
   154→        switch (event.type) {
   155→            case 'session.created':
   156→                console.log('[StreamingTranscription] Session created:', event.session?.id);
   157→                break;
   158→
   159→            case 'session.updated':
   160→                console.log('[StreamingTranscription] Session configured for transcription');
   161→                break;
   162→
   163→            case 'conversation.item.input_audio_transcription.delta':
   164→                // Incremental transcript — stream to UI
   165→                this.emit('delta', {
   166→                    text: event.delta || '',
   167→                    itemId: event.item_id,
   168→                });
   169→                break;
   170→
   171→            case 'conversation.item.input_audio_transcription.completed':
   172→                // Final transcript for this speech turn
   173→                this.emit('completed', {
   174→                    text: event.transcript || '',
   175→                    itemId: event.item_id,
   176→                });
   177→                break;
   178→
   179→            case 'input_audio_buffer.speech_started':
   180→                console.log('[StreamingTranscription] Speech detected');
   181→                this.emit('speech_started');
   182→                break;
   183→
   184→            case 'input_audio_buffer.speech_stopped':
   185→                console.log('[StreamingTranscription] Speech ended');
   186→                this.emit('speech_stopped');
   187→                break;
   188→
   189→            case 'input_audio_buffer.committed':
   190→                console.log('[StreamingTranscription] Audio buffer committed, item:', event.item_id);
   191→                break;
   192→
   193→            case 'error':
   194→                console.error('[StreamingTranscription] Server error:', event.error);
   195→                this.emit('error', {
   196→                    message: event.error?.message || 'Unknown server error',
   197→                });
   198→                break;
   199→
   200→            default:
   201→                // Ignore other event types
   202→                break;
   203→        }
   204→    }
   205→}
   206→
   207→export const streamingTranscription = new StreamingTranscription();
   208→

