    25→ * Supports 3 modes: raw, clean, rewrite
    26→ */
    27→class TextPostProcessor {
    28→    /**
    29→     * Process transcript based on mode
    30→     */
    31→    async processWithMode(
    32→        text: string,
    33→        apiKey: string,
    34→        mode: TranscriptionMode,
    35→        options: Partial<PostProcessingOptions> = {},
    36→    ): Promise<string> {
    37→        if (!text.trim()) return text;
    38→
    39→        // RAW mode: return as-is
    40→        if (mode === 'raw') {
    41→            return text.trim();
    42→        }
    43→
    44→        // CLEAN mode: local processing only
    45→        if (mode === 'clean') {
    46→            return this.processLocal(text, options);
    47→        }
    48→
    49→        // REWRITE mode: local clean + GPT rewrite
    50→        if (mode === 'rewrite') {
    51→            const cleaned = this.processLocal(text, options);
    52→            const prompt = options.systemPrompt || MODE_PROMPTS.rewrite;
    53→            if (prompt && apiKey) {
    54→                try {
    55→                    return await this.gptFormat(cleaned, apiKey, prompt);
    56→                } catch (err) {
    57→                    console.error('[TextPostProcessor] GPT rewrite failed, using cleaned text:', err);
    58→                    return cleaned;
    59→                }
    60→            }
    61→            return cleaned;
    62→        }
    63→
    64→        return text.trim();
    65→    }
    66→
    67→    /**
    68→     * Legacy method — backwards compat
    69→     */
    70→    async process(
    71→        text: string,
    72→        apiKey: string,
    73→        options: Partial<PostProcessingOptions> = {},
    74→    ): Promise<string> {
    75→        return this.processLocal(text, options);
    76→    }
    77→
    78→    /**
    79→     * Local (no API call) post-processing
    80→     */
    81→    private processLocal(text: string, options: Partial<PostProcessingOptions> = {}): string {
    82→        let result = text.trim();
