    87→
    88→        if (options.autoCapitalize !== false) {
    89→            result = this.autoCapitalize(result);
    90→        }
    91→
    92→        if (options.fixPunctuation !== false) {
    93→            result = this.fixPunctuation(result);
    94→        }
    95→
    96→        return result;
    97→    }
    98→
    99→    private removeFillers(text: string): string {
   100→        let result = text;
   101→        for (const pattern of FILLER_PATTERNS) {
   102→            result = result.replace(pattern, '');
   103→        }
   104→        return result.replace(/\s{2,}/g, ' ').trim();
   105→    }
   106→
   107→    private autoCapitalize(text: string): string {
   108→        let result = text.charAt(0).toUpperCase() + text.slice(1);
   109→        result = result.replace(/([.!?]\s+)([a-z])/g, (_, punct, letter) => {
   110→            return punct + letter.toUpperCase();
   111→        });
   112→        return result;
   113→    }
   114→
   115→    private fixPunctuation(text: string): string {
   116→        let result = text;
   117→        result = result.replace(/\s+([.,!?;:])/g, '$1');
   118→        result = result.replace(/([.,!?;:])([A-Za-zÀ-ÿ])/g, '$1 $2');
   119→        if (result.length > 0 && !/[.!?]$/.test(result)) {
   120→            result += '.';
   121→        }
   122→        return result;
   123→    }
   124→
   125→    private async gptFormat(
   126→        text: string,
   127→        apiKey: string,
   128→        systemPrompt: string,
   129→    ): Promise<string> {
   130→        const response = await axios.post(
   131→            'https://api.openai.com/v1/chat/completions',
   132→            {
   133→                model: 'gpt-4o-mini',
   134→                messages: [
   135→                    { role: 'system', content: systemPrompt },
   136→                    { role: 'user', content: text },
   137→                ],
   138→                temperature: 0.3,
   139→                max_tokens: 2048,
   140→            },
   141→            {
   142→                headers: {
   143→                    Authorization: `Bearer ${apiKey}`,
   144→                    'Content-Type': 'application/json',
   145→                },
   146→                timeout: 15000,
   147→            },
   148→        );
   149→
   150→        const formatted = response.data?.choices?.[0]?.message?.content?.trim();
   151→        return formatted || text;
   152→    }
   153→}
