    59→    language: process.env.WHISPER_LANGUAGE || 'auto',
    60→    shortcut: DEFAULT_SHORTCUTS[process.platform as keyof typeof DEFAULT_SHORTCUTS] || DEFAULT_SHORTCUTS.darwin,
    61→    recordingMode: 'push-to-talk',
