     2→/**
     3→ * Audio capture for Renderer process (Web Audio API)
     4→ */
     5→
     6→export const AUDIO_SAMPLE_RATE = 24000;
     7→
     8→class AudioCapture {
     9→    private mediaStream: MediaStream | null = null;
    10→    private audioContext: AudioContext | null = null;
    11→    private analyser: AnalyserNode | null = null;
    12→    private scriptProcessor: ScriptProcessorNode | null = null;
    13→    private visualizationData: Uint8Array = new Uint8Array(128);
    14→    private isRecording = false;
    15→    private onPcmChunk: ((chunk: ArrayBuffer) => void) | null = null;
    16→
    17→    constructor() {
    18→        // Initialize visualization data
    19→        this.visualizationData = new Uint8Array(128);
    20→    }
    21→
    22→    /**
    23→     * Set callback for PCM chunks
    24→     */
    25→    setOnPcmChunk(callback: (chunk: ArrayBuffer) => void) {
    26→        this.onPcmChunk = callback;
    27→    }
    28→
    29→    /**
    30→     * Start audio recording with PCM streaming
    31→     */
    32→    async startRecording(): Promise<void> {
    33→        if (this.isRecording) return;
    34→
    35→        try {
    36→            // Request microphone access
    37→            this.mediaStream = await navigator.mediaDevices.getUserMedia({
    38→                audio: {
    39→                    channelCount: 1,
    40→                    sampleRate: AUDIO_SAMPLE_RATE,
    41→                    echoCancellation: true,
    42→                    noiseSuppression: true,
    43→                    autoGainControl: true,
    44→                },
    45→            });
    46→
    47→            // Setup audio context
    48→            this.audioContext = new AudioContext({ sampleRate: AUDIO_SAMPLE_RATE });
    49→            const source = this.audioContext.createMediaStreamSource(this.mediaStream);
    50→
    51→            // Analyser for UI visualization
    52→            this.analyser = this.audioContext.createAnalyser();
    53→            this.analyser.fftSize = 256;
    54→            this.analyser.smoothingTimeConstant = 0.8;
    55→            source.connect(this.analyser);
    56→
    57→            // ScriptProcessor to capture raw PCM samples for streaming
    58→            // Buffer size 4096 ≈ 170ms at 24kHz
    59→            const bufferSize = 4096;
    60→            this.scriptProcessor = this.audioContext.createScriptProcessor(bufferSize, 1, 1);
    61→
    62→            this.scriptProcessor.onaudioprocess = (event) => {
    63→                if (!this.isRecording) return;
    64→
    65→                const inputData = event.inputBuffer.getChannelData(0); // Float32 [-1, 1]
    66→
    67→                // Convert Float32 -> Int16LE PCM
    68→                const pcmBuffer = new Int16Array(inputData.length);
    69→                for (let i = 0; i < inputData.length; i++) {
    70→                    const sample = Math.max(-1, Math.min(1, inputData[i]));
    71→                    pcmBuffer[i] = sample < 0 ? sample * 0x8000 : sample * 0x7FFF;
    72→                }
    73→
    74→                if (this.onPcmChunk) {
    75→                    this.onPcmChunk(pcmBuffer.buffer as ArrayBuffer);
    76→                }
    77→            };
    78→
    79→            source.connect(this.scriptProcessor);
    80→            this.scriptProcessor.connect(this.audioContext.destination);
    81→
    82→            this.isRecording = true;
    83→            this.updateVisualizationLoop();
    84→
    85→            console.log('Audio recording started (Renderer)');
    86→        } catch (error) {
    87→            console.error('Failed to start audio recording:', error);
    88→            throw error;
    89→        }
    90→    }
    91→
    92→    /**
    93→     * Stop recording
    94→     */
    95→    stopRecording(): void {
    96→        this.isRecording = false;
    97→
    98→        if (this.mediaStream) {
    99→            this.mediaStream.getTracks().forEach(track => track.stop());
   100→            this.mediaStream = null;
   101→        }
   102→
   103→        if (this.scriptProcessor) {
   104→            this.scriptProcessor.disconnect();
   105→            this.scriptProcessor = null;
   106→        }
   107→
   108→        if (this.analyser) {
   109→            this.analyser.disconnect();
   110→            this.analyser = null;
   111→        }
   112→
   113→        if (this.audioContext) {
   114→            this.audioContext.close();
   115→            this.audioContext = null;
   116→        }
   117→    }
   118→
   119→    /**
   120→     * Visualization loop
   121→     */
   122→    private updateVisualizationLoop() {
   123→        if (!this.isRecording || !this.analyser) return;
   124→
   125→        this.analyser.getByteFrequencyData(this.visualizationData);
   126→        requestAnimationFrame(() => this.updateVisualizationLoop());
