     1→import { useState, useEffect, useRef } from 'react';
     2→
     3→export type RecordingState = 'idle' | 'listening' | 'processing' | 'error';
     4→export type RecordingMode = 'push-to-talk' | 'toggle';
     5→
     6→interface RecordingStateHook {
     7→    state: RecordingState;
     8→    mode: RecordingMode;
     9→    errorMessage: string;
    10→    isVisible: boolean;
    11→    recordingDuration: number;
    12→    liveTranscript: string;
    13→    finalTranscript: string;
    14→}
    15→
    16→/**
    17→ * Hook to manage recording state + live streaming transcript from Electron IPC
    18→ */
    19→export function useRecordingState(): RecordingStateHook {
    20→    const [state, setState] = useState<RecordingState>('idle');
    21→    const [mode, setMode] = useState<RecordingMode>('push-to-talk');
    22→    const [errorMessage, setErrorMessage] = useState('');
    23→    const [isVisible, setIsVisible] = useState(false);
    24→    const [recordingDuration, setRecordingDuration] = useState(0);
    25→
    26→    // Streaming transcript state
    27→    const [liveTranscript, setLiveTranscript] = useState('');
    28→    const [finalTranscript, setFinalTranscript] = useState('');
    29→    const currentDeltaText = useRef('');
    30→
    31→    useEffect(() => {
    32→        if (!window.electronAPI) return;
    33→
    34→        // Listen for shortcut pressed → start recording
    35→        window.electronAPI.onShortcutPressed(() => {
    36→            setState('listening');
    37→            setIsVisible(true);
    38→            setErrorMessage('');
    39→            setRecordingDuration(0);
    40→            setLiveTranscript('');
    41→            setFinalTranscript('');
    42→            currentDeltaText.current = '';
    43→        });
    44→
    45→        // Listen for shortcut released → stop recording
    46→        window.electronAPI.onShortcutReleased(() => {
    47→            setState('processing');
    48→        });
    49→
    50→        // Recording state changes
    51→        window.electronAPI.onRecordingState((data: any) => {
    52→            if (data.state) {
    53→                setState(data.state as RecordingState);
    54→            }
    55→        });
    56→
    57→        // Streaming transcript: incremental delta
    58→        window.electronAPI.onTranscriptDelta((data) => {
    59→            currentDeltaText.current += data.text;
    60→            setLiveTranscript(currentDeltaText.current);
    61→        });
    62→
    63→        // Streaming transcript: completed turn
    64→        window.electronAPI.onTranscriptCompleted((data) => {
    65→            setFinalTranscript(data.fullText);
    66→            setLiveTranscript('');
    67→            currentDeltaText.current = '';
    68→        });
    69→
    70→        // Errors
    71→        window.electronAPI.onRecordingError((data: any) => {
    72→            setState('error');
    73→            setErrorMessage(data.message || 'An error occurred');
    74→            setTimeout(() => {
    75→                setIsVisible(false);
    76→                setState('idle');
    77→            }, 2000);
    78→        });
    79→
    80→        // Transcription complete → hide overlay
    81→        window.electronAPI.onTranscriptionComplete(() => {
    82→            setState('idle');
    83→            setIsVisible(false);
    84→            setRecordingDuration(0);
    85→            setLiveTranscript('');
    86→            setFinalTranscript('');
    87→            currentDeltaText.current = '';
    88→        });
    89→    }, []);
    90→
    91→    // Timer for recording duration
    92→    useEffect(() => {
    93→        if (state === 'listening') {
    94→            const interval = setInterval(() => {
    95→                setRecordingDuration((prev) => prev + 1);
    96→            }, 1000);
    97→            return () => clearInterval(interval);
    98→        }
    99→    }, [state]);
   100→
   101→    return {
   102→        state,
   103→        mode,
   104→        errorMessage,
   105→        isVisible,
   106→        recordingDuration,
   107→        liveTranscript,
   108→        finalTranscript,
   109→    };
   110→}
