     1→import React, { useEffect, useRef } from 'react';
     2→import './AudioVisualizer.css';
     3→
     4→interface AudioVisualizerProps {
     5→    audioData: Uint8Array;
     6→    state: 'idle' | 'listening' | 'processing' | 'error';
     7→}
     8→
     9→/**
    10→ * Circular audio visualizer component
    11→ */
    12→export function AudioVisualizer({ audioData, state }: AudioVisualizerProps) {
    13→    const canvasRef = useRef<HTMLCanvasElement>(null);
    14→
    15→    useEffect(() => {
    16→        const canvas = canvasRef.current;
    17→        if (!canvas) return;
    18→
    19→        const ctx = canvas.getContext('2d');
    20→        if (!ctx) return;
    21→
    22→        // Set canvas size
    23→        const size = 200;
    24→        canvas.width = size;
    25→        canvas.height = size;
    26→
    27→        const centerX = size / 2;
    28→        const centerY = size / 2;
    29→        const radius = 60;
    30→
    31→        // Clear canvas
    32→        ctx.clearRect(0, 0, size, size);
    33→
    34→        if (state === 'idle') {
    35→            // Draw idle state: simple pulsing dot
    36→            drawIdleState(ctx, centerX, centerY, radius);
    37→        } else if (state === 'listening') {
    38→            // Draw listening state: circular waveform
    39→            drawWaveform(ctx, centerX, centerY, radius, audioData);
    40→        } else if (state === 'processing') {
    41→            // Draw processing state: spinning loader
    42→            drawProcessing(ctx, centerX, centerY, radius);
    43→        } else if (state === 'error') {
    44→            // Draw error state: red pulsing
    45→            drawError(ctx, centerX, centerY, radius);
    46→        }
    47→    }, [audioData, state]);
    48→
    49→    return <canvas ref={canvasRef} className="audio-visualizer" />;
    50→}
    51→
    52→/**
    53→ * Draw idle state
    54→ */
    55→function drawIdleState(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
    56→    const time = Date.now() / 1000;
    57→    const pulseScale = 1 + Math.sin(time * 2) * 0.1;
    58→
    59→    ctx.beginPath();
    60→    ctx.arc(x, y, radius * 0.3 * pulseScale, 0, Math.PI * 2);
    61→    ctx.fillStyle = 'rgba(0, 217, 255, 0.3)';
    62→    ctx.fill();
    63→
    64→    // Glow
    65→    ctx.shadowBlur = 20;
    66→    ctx.shadowColor = '#00d9ff';
    67→}
    68→
    69→/**
    70→ * Draw circular waveform
    71→ */
    72→function drawWaveform(
    73→    ctx: CanvasRenderingContext2D,
    74→    x: number,
    75→    y: number,
    76→    radius: number,
    77→    audioData: Uint8Array
    78→) {
    79→    const bars = 64; // Number of bars around the circle
    80→    const barWidth = 3;
    81→    const gap = 2;
    82→
    83→    for (let i = 0; i < bars; i++) {
    84→        const dataIndex = Math.floor((i / bars) * audioData.length);
    85→        const amplitude = audioData[dataIndex] / 255; // Normalize to 0-1
    86→
    87→        const angle = (i / bars) * Math.PI * 2 - Math.PI / 2;
    88→        const barHeight = amplitude * 40 + 5;
    89→
    90→        const x1 = x + Math.cos(angle) * radius;
    91→        const y1 = y + Math.sin(angle) * radius;
    92→        const x2 = x + Math.cos(angle) * (radius + barHeight);
    93→        const y2 = y + Math.sin(angle) * (radius + barHeight);
    94→
    95→        ctx.beginPath();
    96→        ctx.moveTo(x1, y1);
    97→        ctx.lineTo(x2, y2);
    98→        ctx.lineWidth = barWidth;
    99→        ctx.strokeStyle = `rgba(0, 217, 255, ${0.5 + amplitude * 0.5})`;
   100→        ctx.shadowBlur = 10;
   101→        ctx.shadowColor = '#00d9ff';
   102→        ctx.stroke();
   103→    }
   104→
   105→    // Center circle
   106→    ctx.beginPath();
   107→    ctx.arc(x, y, radius * 0.6, 0, Math.PI * 2);
   108→    ctx.fillStyle = 'rgba(10, 10, 15, 0.8)';
   109→    ctx.fill();
   110→}
   111→
   112→/**
   113→ * Draw processing spinner
   114→ */
   115→function drawProcessing(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
   116→    const time = Date.now() / 1000;
   117→    const rotation = time * 2; // Speed of rotation
   118→
   119→    for (let i = 0; i < 12; i++) {
   120→        const angle = (i / 12) * Math.PI * 2 + rotation;
   121→        const opacity = (i / 12);
   122→
   123→        const x1 = x + Math.cos(angle) * radius * 0.6;
   124→        const y1 = y + Math.sin(angle) * radius * 0.6;
   125→        const x2 = x + Math.cos(angle) * radius;
   126→        const y2 = y + Math.sin(angle) * radius;
   127→
   128→        ctx.beginPath();
   129→        ctx.moveTo(x1, y1);
   130→        ctx.lineTo(x2, y2);
   131→        ctx.lineWidth = 3;
   132→        ctx.strokeStyle = `rgba(0, 217, 255, ${opacity})`;
   133→        ctx.stroke();
   134→    }
   135→}
   136→
   137→/**
   138→ * Draw error state
   139→ */
   140→function drawError(ctx: CanvasRenderingContext2D, x: number, y: number, radius: number) {
   141→    const time = Date.now() / 1000;
   142→    const pulseScale = 1 + Math.sin(time * 4) * 0.15;
   143→
   144→    // Outer pulse
   145→    ctx.beginPath();
   146→    ctx.arc(x, y, radius * pulseScale, 0, Math.PI * 2);
   147→    ctx.strokeStyle = 'rgba(255, 71, 87, 0.6)';
   148→    ctx.lineWidth = 3;
   149→    ctx.shadowBlur = 20;
   150→    ctx.shadowColor = '#ff4757';
   151→    ctx.stroke();
   152→
   153→    // Inner circle
   154→    ctx.beginPath();
   155→    ctx.arc(x, y, radius * 0.5, 0, Math.PI * 2);
   156→    ctx.fillStyle = 'rgba(255, 71, 87, 0.3)';
   157→    ctx.fill();
   158→}
