.overlay-container {
    width: 100vw;
    height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: opacity var(--transition-medium);
}

.overlay-container.visible {
    opacity: 1;
}

.overlay-container.hidden {
    opacity: 0;
    pointer-events: none;
}

.overlay-window {
    position: relative;
    width: 340px;
    min-height: 280px;
    max-height: 420px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--bg-overlay);
    border-radius: 28px;
    backdrop-filter: blur(20px);
    box-shadow: var(--shadow-overlay);
    transition: all var(--transition-medium);
    overflow: hidden;
}

/* Glow ring effect */
.glow-ring {
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    border-radius: 30px;
    background: linear-gradient(135deg,
            var(--accent-primary),
            transparent,
            var(--accent-primary));
    opacity: 0;
    transition: opacity var(--transition-medium);
    z-index: -1;
}
